def is_palindrome(n):
    return str(n) == str(n)[::-1]

def generate_palindromes(limit):
    palindromes = []
    for i in range(1, limit):
        if is_palindrome(i):
            palindromes.append(i)
    return palindromes

def can_be_sum_of_two_palindromes(n, palindromes):
    for p in palindromes:
        if p > n:
            break
        if is_palindrome(n - p):
            return True
    return False

